import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { authAPI } from '../api';

function Login() {
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const response = await authAPI.login(mobileNumber, otp);

      if (response.data.success) {
        const userData = response.data.data;
        localStorage.setItem('user', JSON.stringify(userData));

        if (userData.role === 'ADMIN') {
          navigate('/admin');
        } else {
          navigate('/voter');
        }
      } else {
        setError(response.data.message);
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-container">
      <div className="card">
        <div className="header">
          <h1>BlockVOTE</h1>
          <p>Blockchain Voting System</p>
        </div>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Mobile Number</label>
            <input
              type="text"
              value={mobileNumber}
              onChange={(e) => setMobileNumber(e.target.value)}
              placeholder="Enter 10-digit mobile number"
              required
              maxLength="10"
            />
          </div>

          <div className="form-group">
            <label>OTP</label>
            <input
              type="text"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              placeholder="Enter OTP (123456)"
              required
              maxLength="6"
            />
          </div>

          {error && <div className="alert alert-error">{error}</div>}

          <button type="submit" className="btn btn-primary" disabled={loading} style={{ width: '100%', marginBottom: '10px' }}>
            {loading ? 'Logging in...' : 'Login'}
          </button>

          <button
            type="button"
            onClick={() => navigate('/register')}
            className="btn btn-secondary"
            style={{ width: '100%' }}
          >
            Register as New Voter
          </button>
        </form>

        <div style={{ marginTop: '20px', padding: '15px', background: '#edf2f7', borderRadius: '4px' }}>
          <p style={{ margin: '0 0 10px', fontWeight: '600' }}>Demo Credentials:</p>
          <p style={{ margin: '5px 0', fontSize: '14px' }}>
            <strong>Admin:</strong> 9999999999
          </p>
          <p style={{ margin: '5px 0', fontSize: '14px' }}>
            <strong>Voter 1:</strong> 8888888888
          </p>
          <p style={{ margin: '5px 0', fontSize: '14px' }}>
            <strong>Voter 2:</strong> 7777777777
          </p>
          <p style={{ margin: '5px 0', fontSize: '14px' }}>
            <strong>Voter 3:</strong> 6666666666
          </p>
          <p style={{ margin: '10px 0 0', fontSize: '14px' }}>
            <strong>OTP for all:</strong> 123456
          </p>
        </div>
      </div>
    </div>
  );
}

export default Login;
